class BinarySearchTree:
    def __init__(self):
        self.root = None

    def insert(self, char):
        if self.root is None:
            self.root = char
        else:
            self._insert(self.root, char)

    def _insert(self, current_node, char):
        if char < current_node:
            if current_node.left is None:
                current_node.left = char
            else:
                self._insert(current_node.left, char)
        elif char > current_node:
            if current_node.right is None:
                current_node.right = char
            else:
                self._insert(current_node.right, char)

def process_sequence(sequence):
    tree = BinarySearchTree()
    for char in sequence:
        tree.insert(char.lower())
    return tree

